import '@/app/ui/global.css';
//import { createFont } from 'next/font/local';
//import { FontProvider, useFont } from
import { FontProvider, useFont } from '@/app/ui/fontpicker';
import { hin115_font, ing115_font } from '@/fonts';
import { Metadata } from 'next';

export const metadata: Metadata = {
  title: {
    template: '%s | ᴀcme dᴀshboᴀrd',
    default: 'ᴀcme dᴀshboᴀrd',
  },
  description: 'The official Next.js Learn Dashboard built with App Router.',
  metadataBase: new URL('https://next-learn-dashboard.vercel.sh'),
};
export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const { selectedFont } = useFont()

  const getFontClass = () => {
    switch (selectedFont) {
      case 'hin115':
        return hin115_font.className
      default:
        return ing115_font.className
    }
  }
  // className={getFontClass()}
  return (
    <html lang="en">
      <body className={`${hin115_font.className} antialiased`}>{children}</body>
    </html>
  );
}
